sql:
SELECT reading_id, timestamp
FROM electrical_readings
WHERE sensor_id = 'Sensor1';

SELECT DISTINCT location
FROM electrical_readings
WHERE voltage > (SELECT value FROM settings WHERE key = 'alert_threshold');

external_knowledge:
- 'fiery breath of gasoline' metaphorically refers to gasoline-powered vehicles;
- 'traversed more than 100,000 miles' means the mileage is over 100,000 miles;
- 'average waves of voltage', 'tides of current', and 'resistance they have faced' are metaphorical expressions referring to the average voltage, current, and resistance of the vehicle's electrical readings.

- Experienced handlers: Users who have successfully resolved alerts;
- Pretty significant number of miles: More than 10,000 miles;
- Odometer readings: Vehicle mileage;
- Sorted out: Resolved alerts;

- 'Storm-tossed' metaphorically indicates vehicles that have encountered multiple 'Current Surge' alerts; 
- 'Electrical tempests' refer to alerts of type 'Current Surge'; 
- 'Recent past' refers to the period in the last 30 days.

sql:
SELECT engine_type_name 
FROM engine_types 
WHERE efficiency = (SELECT MAX(efficiency) FROM engine_types);

SELECT COUNT(DISTINCT vehicle_id) AS RecentDiagnosedVehicles 
FROM diagnostics 
WHERE test_date >= DATE('now', '-12 month');

SELECT vehicle_id, model, engine_type
FROM vehicles
WHERE mileage > (
  SELECT AVG(mileage) FROM vehicles
);
